} }

draw((0,0)--(1,3));
draw((3,3)--(4,0));

label("$A$",(0,0),SW);
label("$B$",(4,0),SE);
label("$C$",(4,3),NE);
label("$D$",(0,3),NW);
label("$E$",(1,3),N);
label("$F$",(3,3),N);

[/asy]

solution:
$\text{\emph{Strategy: Add areas.}}$

